"use client"

import Link from "next/link"
import { ArrowLeft } from "lucide-react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { useToolsData } from "@/hooks/use-tools-data"

const PERSONAL_ALLOWANCE = 12_570
const DIVIDEND_ALLOWANCE = 500
const BASIC_LIMIT = 50_270
const HIGHER_LIMIT = 125_140
const RATE_BASIC = 8.75
const RATE_HIGHER = 33.75
const RATE_ADDITIONAL = 39.35

function calcDividendTax(
  dividendIncome: number,
  otherIncome: number
): {
  totalIncome: number
  personalAllowanceUsed: number
  dividendAllowanceUsed: number
  taxableDividends: number
  taxBasic: number
  taxHigher: number
  taxAdditional: number
  totalDividendTax: number
  afterTaxDividends: number
} {
  const totalIncome = dividendIncome + otherIncome
  let personalAllowance = PERSONAL_ALLOWANCE
  const personalAllowanceUsedBySalary = Math.min(otherIncome, personalAllowance)
  personalAllowance -= personalAllowanceUsedBySalary
  const personalAllowanceUsedByDividends = Math.min(dividendIncome, personalAllowance)
  personalAllowance -= personalAllowanceUsedByDividends

  const dividendAllowanceUsed = Math.min(DIVIDEND_ALLOWANCE, dividendIncome - personalAllowanceUsedByDividends)
  const dividendsAfterPA = dividendIncome - personalAllowanceUsedByDividends
  const dividendsAfterAllowance = Math.max(0, dividendsAfterPA - dividendAllowanceUsed)

  let taxableInBand = 0
  let taxBasic = 0
  let taxHigher = 0
  let taxAdditional = 0

  const salaryAfterPA = otherIncome - personalAllowanceUsedBySalary
  let bandUsed = Math.max(0, salaryAfterPA)

  const HIGHER_BAND_SIZE = HIGHER_LIMIT - BASIC_LIMIT // 72870
  const basicLimitRemaining = Math.max(0, BASIC_LIMIT - bandUsed)
  const firstChunk = Math.min(dividendsAfterAllowance, basicLimitRemaining)
  taxBasic = firstChunk * (RATE_BASIC / 100)
  bandUsed += firstChunk

  const secondChunk = Math.min(dividendsAfterAllowance - firstChunk, HIGHER_BAND_SIZE)
  taxHigher = secondChunk * (RATE_HIGHER / 100)
  bandUsed += secondChunk

  const additionalTaxable = Math.max(0, dividendsAfterAllowance - firstChunk - secondChunk)
  taxAdditional = additionalTaxable * (RATE_ADDITIONAL / 100)

  const totalDividendTax = taxBasic + taxHigher + taxAdditional
  const afterTaxDividends = dividendIncome - totalDividendTax

  return {
    totalIncome,
    personalAllowanceUsed: personalAllowanceUsedBySalary + personalAllowanceUsedByDividends,
    dividendAllowanceUsed: Math.min(DIVIDEND_ALLOWANCE, dividendsAfterPA),
    taxableDividends: dividendsAfterAllowance,
    taxBasic,
    taxHigher,
    taxAdditional,
    totalDividendTax,
    afterTaxDividends,
  }
}

export default function DividendTaxCalculatorPage() {
  const { data, update } = useToolsData()
  const { dividendIncome, otherIncome } = data.dividendTaxCalc

  const result = calcDividendTax(dividendIncome, otherIncome)

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center gap-3 sm:gap-4">
        <Link href="/tools">
          <Button variant="outline" size="icon" className="shrink-0">
            <ArrowLeft className="h-4 w-4" />
          </Button>
        </Link>
        <div className="min-w-0">
          <h1 className="text-lg md:text-2xl font-bold text-foreground">Dividend Tax Calculator</h1>
          <p className="text-sm text-muted-foreground">
            2024/25: Personal allowance £12,570, Dividend allowance £500. Salary uses allowance first.
          </p>
        </div>
      </div>

      <Card className="card-panel rounded-2xl">
        <CardHeader>
          <CardTitle className="text-base">Income</CardTitle>
        </CardHeader>
        <CardContent className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="space-y-2">
            <Label className="text-muted-foreground">Dividend income (£)</Label>
            <Input
              type="number"
              min={0}
              step={100}
              value={dividendIncome || ""}
              onChange={(e) =>
                update("dividendTaxCalc", { dividendIncome: Number(e.target.value) || 0 })
              }
              placeholder="0"
              className="bg-muted/50 border-border"
            />
          </div>
          <div className="space-y-2">
            <Label className="text-muted-foreground">Other income / Salary (£)</Label>
            <Input
              type="number"
              min={0}
              step={100}
              value={otherIncome || ""}
              onChange={(e) =>
                update("dividendTaxCalc", { otherIncome: Number(e.target.value) || 0 })
              }
              placeholder="0"
              className="bg-muted/50 border-border"
            />
          </div>
        </CardContent>
      </Card>

      <Card className="card-panel rounded-2xl">
        <CardHeader>
          <CardTitle className="text-base">Result</CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 text-sm">
            <div className="rounded-lg bg-muted/50 border border-border p-4">
              <span className="text-muted-foreground">Total income</span>
              <p className="font-semibold text-foreground text-lg mt-1">
                £{result.totalIncome.toFixed(2)}
              </p>
            </div>
            <div className="rounded-lg bg-muted/50 border border-border p-4">
              <span className="text-muted-foreground">Personal allowance used</span>
              <p className="font-semibold text-foreground text-lg mt-1">
                £{result.personalAllowanceUsed.toFixed(2)}
              </p>
            </div>
            <div className="rounded-lg bg-muted/50 border border-border p-4">
              <span className="text-muted-foreground">Dividend allowance used</span>
              <p className="font-semibold text-foreground text-lg mt-1">
                £{result.dividendAllowanceUsed.toFixed(2)}
              </p>
            </div>
            <div className="rounded-lg bg-muted/50 border border-border p-4">
              <span className="text-muted-foreground">Taxable dividends</span>
              <p className="font-semibold text-foreground text-lg mt-1">
                £{result.taxableDividends.toFixed(2)}
              </p>
            </div>
            <div className="rounded-lg bg-muted/50 border border-border p-4">
              <span className="text-muted-foreground">Dividend tax due</span>
              <p className="font-semibold text-mp-amber text-lg mt-1">
                £{result.totalDividendTax.toFixed(2)}
              </p>
            </div>
            <div className="rounded-lg bg-muted/50 border border-border p-4">
              <span className="text-muted-foreground">Dividends after tax</span>
              <p className="font-semibold text-mp-green text-lg mt-1">
                £{result.afterTaxDividends.toFixed(2)}
              </p>
            </div>
          </div>
          <div className="rounded-lg bg-muted/50 border border-border p-4 text-sm">
            <p className="text-muted-foreground mb-2">Bands: Basic 8.75% (up to £50,270), Higher 33.75% (£50,271–£125,140), Additional 39.35% (over £125,140).</p>
            <p className="text-muted-foreground">
              Basic: £{result.taxBasic.toFixed(2)} · Higher: £{result.taxHigher.toFixed(2)} · Additional: £{result.taxAdditional.toFixed(2)}
            </p>
          </div>
        </CardContent>
      </Card>
    </div>
  )
}
